#!/usr/bin/env bash
#===============================================================================
# DEPLOY COMPLETO - devs-permissions-cockpit v1.0.0
# Este script é auto-contido: extrai, instala e configura tudo.
#
# USO:
#   curl -sL <URL> | sudo bash        # ou
#   sudo bash deploy-to-server.sh      # se copiado manualmente
#===============================================================================

set -euo pipefail

if [[ -t 1 ]]; then
    R='\033[0;31m' G='\033[0;32m' Y='\033[1;33m' B='\033[0;34m' N='\033[0m'
else
    R='' G='' Y='' B='' N=''
fi
info()  { echo -e "${G}[INFO]${N} $*"; }
warn()  { echo -e "${Y}[WARN]${N} $*"; }
error() { echo -e "${R}[ERRO]${N} $*" >&2; }

if [[ $EUID -ne 0 ]]; then
    error "Execute como root: sudo bash $0"
    exit 1
fi

# Verificar Cockpit
if ! command -v cockpit-bridge &>/dev/null || [[ ! -d "/usr/share/cockpit" ]]; then
    error "Cockpit nao encontrado. Instale primeiro:"
    echo "  sudo dnf install cockpit && sudo systemctl enable --now cockpit.socket"
    exit 1
fi

info "Extraindo arquivos..."
WORK_DIR=$(mktemp -d)
trap 'rm -rf "$WORK_DIR"' EXIT

# Payload base64 embutido
base64 -d << 'PAYLOAD' | tar -xzf - -C "$WORK_DIR"

PAYLOAD

cd "$WORK_DIR/devs-permissions-cockpit"

info "Instalando plugin Cockpit..."
mkdir -p /usr/share/cockpit/devs-permissions
install -m 644 src/manifest.json /usr/share/cockpit/devs-permissions/
install -m 644 src/index.html /usr/share/cockpit/devs-permissions/
install -m 644 src/devs-permissions.js /usr/share/cockpit/devs-permissions/
install -m 644 src/devs-permissions.css /usr/share/cockpit/devs-permissions/

info "Instalando bridge helper..."
mkdir -p /usr/libexec/devs-permissions
install -m 755 bridge/cockpit-helper.sh /usr/libexec/devs-permissions/

info "Criando diretorios de dados..."
mkdir -p /etc/devs-permissions
mkdir -p -m 750 /var/lib/devs_permissions/temp_access
mkdir -p -m 750 /var/lib/devs_permissions/requests
mkdir -p -m 750 /var/log/devs_audit/sessions
mkdir -p -m 750 /var/backups/devs_permissions

# Copiar scripts se existem em /root/bin/
if [[ -f /root/bin/devs_permissions_manager.sh ]]; then
    info "Copiando manager de /root/bin/ para /usr/libexec/devs-permissions/..."
    install -m 755 /root/bin/devs_permissions_manager.sh /usr/libexec/devs-permissions/
fi

if [[ -f /root/bin/devs_permissions.conf ]] && [[ ! -f /etc/devs-permissions/devs_permissions.conf ]]; then
    info "Copiando config de /root/bin/ para /etc/devs-permissions/..."
    install -m 644 /root/bin/devs_permissions.conf /etc/devs-permissions/
fi

info "Reiniciando Cockpit..."
systemctl try-restart cockpit.socket 2>/dev/null || warn "Nao foi possivel reiniciar cockpit.socket"

echo ""
info "============================================="
info " Instalacao concluida!"
info "============================================="
echo ""
echo "  Acesse: https://$(hostname -f 2>/dev/null || hostname):9090"
echo "  Menu lateral: DevOps Permissions"
echo ""

# Verificar se tudo esta no lugar
if [[ -x /usr/libexec/devs-permissions/devs_permissions_manager.sh ]]; then
    info "Manager: OK"
else
    warn "Manager NAO encontrado em /usr/libexec/devs-permissions/"
    echo "  Copie manualmente:"
    echo "    cp /root/bin/devs_permissions_manager.sh /usr/libexec/devs-permissions/"
    echo "    chmod +x /usr/libexec/devs-permissions/devs_permissions_manager.sh"
fi

if [[ -f /etc/devs-permissions/devs_permissions.conf ]]; then
    info "Config: OK"
else
    warn "Config NAO encontrada em /etc/devs-permissions/"
    echo "  Copie manualmente:"
    echo "    cp /root/bin/devs_permissions.conf /etc/devs-permissions/"
fi

echo ""
info "Para desinstalar: rm -rf /usr/share/cockpit/devs-permissions /usr/libexec/devs-permissions/cockpit-helper.sh"
